class Solution:
    def reverseKGroup(self, head, k):
        cur = head; count = 0
        while cur and count < k:
            cur = cur.next; count += 1
        if count == k:
            rev = self._rev(head, k)
            head.next = self.reverseKGroup(cur, k)
            return rev
        return head
    def _rev(self, head, k):
        prev = None; cur = head
        for _ in range(k):
            nxt = cur.next; cur.next = prev; prev = cur; cur = nxt
        return prev

