class Solution {
    ListNode* rev(ListNode* a, ListNode* b) {
        ListNode* prev = b;
        while (a != b) { auto* n = a->next; a->next = prev; prev = a; a = n; }
        return prev;
    }
public:
    ListNode* reverseKGroup(ListNode* head, int k) {
        ListNode* cur = head;
        for (int i = 0; i < k; i++) if (!cur) return head;
        cur = cur->next;
        head->next = reverseKGroup(cur, k);
        return rev(head, cur);
    }
};
